<?php
namespace App\Livewire\Forms; use Livewire\Form; class MedicationAdministrationForm extends Form { public ?int $medicine_id=null; public ?int $prescription_item_id=null; public string $medicine_name_snapshot=''; public string $dose=''; public string $route='oral'; public ?string $frequency=null; public ?string $scheduled_at=null; public ?string $notes=null; public function rules(): array { return ['medicine_name_snapshot'=>['required'],'dose'=>['required'],'route'=>['required']]; } public function validationAttributes(): array { return ['medicine_name_snapshot'=>'dawa']; } public function normalize(): array { return $this->all(); } public function fillFromModel($m): void { $this->fill($m->only(array_keys($this->normalize()))); } public function resetForm(): void { $this->reset(); $this->route='oral'; } }
